def solve(weight_kg, height_cm, age_years, gender):
    # Step 1: Calculate the REE for a male patient using the Harris-Benedict formula
    ree_male = (66 + (13.7 * weight_kg) + (5 * height_cm) - (6.8 * age_years)) * 1.1
    yield {
        "step_name": "calculate_ree_for_male",
        "step_description": "Calculate the Resting Energy Expenditure (REE) for a male patient using the Harris-Benedict formula.",
        "step_result": ree_male,
        "unit": "kcal/day"
    }

    # Step 2: Calculate the REE for a female patient using the Harris-Benedict formula
    ree_female = (655 + (9.6 * weight_kg) + (1.7 * height_cm) - (4.7 * age_years)) * 1.1
    yield {
        "step_name": "calculate_ree_for_female",
        "step_description": "Calculate the Resting Energy Expenditure (REE) for a female patient using the Harris-Benedict formula.",
        "step_result": ree_female,
        "unit": "kcal/day"
    }

    # Step 3: Select the appropriate REE value based on the patient's gender
    if gender == "Male":
        ree_value = ree_male
    else:
        ree_value = ree_female
    yield {
        "step_name": "select_ree_based_on_gender",
        "step_description": "Select the appropriate REE value based on the patient's gender.",
        "step_result": ree_value,
        "unit": "kcal/day"
    }

    return ree_value
